14	// fakeHealth is a hand-driven per-path liveness verdict so a test can force the exact
15	// hub-loss (all DOWN) / partial (some UP) states the controller must distinguish.
16	type fakeHealth struct{ state telemetry.PathState }
17	
18	func (f *fakeHealth) State() telemetry.PathState { return f.state }
19	
20	// recordingRemote records the last endpoint SetPeerRemote was pointed at and how many
21	// times, standing in for the live Bind so the switch is observable without an engine.
22	type recordingRemote struct {
23		last  netip.AddrPort
24		calls int
25	}
26	
27	func (r *recordingRemote) SetPeerRemote(ap netip.AddrPort) {
28		r.last = ap
29		r.calls++
30	}
31	
32	func discardLogger(t *testing.T) log.Logger {
33		t.Helper()
34		lg, err := log.New("error", io.Discard)
35		if err != nil {
36			t.Fatalf("build logger: %v", err)
37		}
38		return lg
39	}
40	
41	func mustEndpoints(t *testing.T, ss ...string) []netip.AddrPort {
42		t.Helper()
43		eps := make([]netip.AddrPort, len(ss))
44		for i, s := range ss {
45			ap, err := netip.ParseAddrPort(s)
46			if err != nil {
47				t.Fatalf("parse endpoint %q: %v", s, err)
48			}
49			eps[i] = ap
50		}
51		return eps
52	}
53	
54	const testSettle = 3 * time.Second
55	
56	// TestHubFailoverSwitchesOnHubLoss is the core acceptance: with a 2-endpoint list,
57	// forcing ALL paths to endpoint#1 DOWN switches the peer remote to endpoint#2 AND
58	// initiates exactly one re-handshake — while ANY path being UP takes no action at all
59	// (hub loss = EVERY path down, distinct from a single path failing).
60	func TestHubFailoverSwitchesOnHubLoss(t *testing.T) {
61		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
62		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateUp}}
63		rem := &recordingRemote{}
64		handshakes := 0
65		clk := &fakeClock{now: time.Unix(1000, 0)}
66		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
67	
68		// Both paths UP → no failover, even long after the settle dwell.
69		clk.advance(10 * time.Second)
70		h.check()
71		if rem.calls != 0 || handshakes != 0 {
72			t.Fatalf("failover fired while a path was UP: remote switches=%d handshakes=%d", rem.calls, handshakes)
73		}
74		if h.idx != 0 {
75			t.Fatalf("active index moved off 0 while a path was up: %d", h.idx)
76		}
77	
78		// Hub loss: every path DOWN. The settle dwell since construction has elapsed (+10s).
79		hp[0].(*fakeHealth).state = telemetry.StateDown
80		hp[1].(*fakeHealth).state = telemetry.StateDown
81		h.check()
82	
83		if rem.calls != 1 {
84			t.Fatalf("expected exactly one remote switch on hub loss, got %d", rem.calls)
85		}
86		if rem.last != eps[1] {
87			t.Fatalf("switched remote = %v, want standby endpoint#2 %v", rem.last, eps[1])
88		}
89		if handshakes != 1 {
90			t.Fatalf("expected exactly one re-handshake on hub loss, got %d", handshakes)
91		}
92		if h.idx != 1 {
93			t.Fatalf("active index = %d, want 1 (advanced to the standby)", h.idx)
94		}
95	}
96	
97	// TestHubFailoverPartialDownNoFailover pins the load-bearing acceptance property that
98	// hub loss is EVERY path DOWN, distinct from a single-path failure (which the per-path
99	// schedulers already handle). With a 2-endpoint list and the settle dwell fully elapsed
100	// — so a broken "any path down" detector WOULD advance — one path UP and one path DOWN
101	// must take NO hub-failover action: no remote switch, no re-handshake, no index move.
102	// This is the case none of the both-Up / both-Down tests exercise; without it, a
103	// regression of allDownLocked from all-down to any-down would pass the whole suite.
104	func TestHubFailoverPartialDownNoFailover(t *testing.T) {
105		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
106		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateDown}}
107		rem := &recordingRemote{}
108		handshakes := 0
109		clk := &fakeClock{now: time.Unix(1000, 0)}
110		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
111	
112		// Settle dwell elapsed: an any-down detector would fire here; an all-down one must not.
113		clk.advance(testSettle + time.Second)
114		h.check()
115	
116		if rem.calls != 0 || handshakes != 0 {
117			t.Fatalf("hub failover fired on a partial-down state (one path UP): remote switches=%d handshakes=%d — hub loss must require EVERY path down", rem.calls, handshakes)
118		}
119		if h.idx != 0 {
120			t.Fatalf("active index moved off 0 while a path was UP: %d (single-path loss must not advance the hub)", h.idx)
121		}
122	}
123	
124	// TestHubFailoverSingleEndpointNoAction is the GUARD: a SINGLE-endpoint list must take
125	// NO failover action even under sustained hub loss — no remote switch, no re-handshake,
126	// no index movement — so a one-concentrator deployment behaves EXACTLY as pre-T57. It is
127	// non-vacuous: absent the len<2 guard, the wrap arithmetic (0+1)%1==0 would "switch" to
128	// the same endpoint and fire a re-handshake, which this asserts never happens.
129	func TestHubFailoverSingleEndpointNoAction(t *testing.T) {
130		eps := mustEndpoints(t, "203.0.113.1:51820")
131		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
132		rem := &recordingRemote{}
133		handshakes := 0
134		clk := &fakeClock{now: time.Unix(1000, 0)}
135		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
136	
137		for i := 0; i < 5; i++ {
138			clk.advance(time.Minute)
139			h.check()
140		}
141		if rem.calls != 0 {
142			t.Fatalf("single-endpoint list switched the remote %d times, want 0", rem.calls)
143		}
144		if handshakes != 0 {
145			t.Fatalf("single-endpoint list re-handshaked %d times, want 0", handshakes)
146		}
147		if h.idx != 0 {
148			t.Fatalf("single-endpoint list moved active index to %d, want 0", h.idx)
149		}
150	}
151	
152	// TestHubFailoverReArmsAndWraps proves detection re-arms against the NEW active endpoint
153	// and, at the end of the list, WRAPS to index 0 (the documented end-of-list policy). With
154	// a 2-endpoint list held fully DOWN, successive settle-separated checks advance 0→1→0.
155	func TestHubFailoverReArmsAndWraps(t *testing.T) {
156		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
157		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
158		rem := &recordingRemote{}
159		handshakes := 0
160		clk := &fakeClock{now: time.Unix(1000, 0)}
161		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
162	
163		// First advance: 0 → 1 (settle since construction has elapsed).
164		clk.advance(testSettle + time.Second)
165		h.check()
166		if h.idx != 1 || rem.last != eps[1] || rem.calls != 1 {
167			t.Fatalf("first advance: idx=%d last=%v calls=%d, want idx=1 last=%v calls=1", h.idx, rem.last, rem.calls, eps[1])
168		}
169	
170		// Re-arm on the new endpoint, still fully down: after another settle, wrap 1 → 0.
171		clk.advance(testSettle + time.Second)
172		h.check()
173		if h.idx != 0 || rem.last != eps[0] || rem.calls != 2 {
174			t.Fatalf("wrap advance: idx=%d last=%v calls=%d, want idx=0 last=%v calls=2 (wrap to index 0)", h.idx, rem.last, rem.calls, eps[0])
175		}
176		if handshakes != 2 {
177			t.Fatalf("re-handshakes=%d, want 2 (one per advance)", handshakes)
178		}
179	}
180	
181	// TestHubFailoverSettleDwellDefersReAdvance proves the settle dwell prevents a premature
182	// second advance: right after a switch, a STILL-DOWN reading (which is expected while the
183	// new endpoint's echoes have not yet returned) must NOT skip to the next endpoint until
184	// the dwell elapses. Without this, a healthy standby would be skipped on the very next
185	// tick before its liveness could recover.
186	func TestHubFailoverSettleDwellDefersReAdvance(t *testing.T) {
187		realEps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820", "192.0.2.9:51820")
188		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
189		rem := &recordingRemote{}
190		handshakes := 0
191		clk := &fakeClock{now: time.Unix(1000, 0)}
192		h := newHubFailover(realEps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
193	
194		// First advance 0 → 1.
195		clk.advance(testSettle + time.Second)
196		h.check()
197		if rem.calls != 1 || h.idx != 1 {
198			t.Fatalf("first advance: calls=%d idx=%d, want 1 and 1", rem.calls, h.idx)
199		}
200	
201		// Within the dwell (< settle since the switch): no second advance despite still-down.
202		clk.advance(testSettle - time.Millisecond)
203		h.check()
204		if rem.calls != 1 || h.idx != 1 {
205			t.Fatalf("advanced within settle dwell: calls=%d idx=%d, want no change (1,1)", rem.calls, h.idx)
206		}
207	
208		// Dwell elapsed: now advance 1 → 2.
209		clk.advance(2 * time.Millisecond)
210		h.check()
211		if rem.calls != 2 || h.idx != 2 || rem.last != realEps[2] {
212			t.Fatalf("advance after dwell: calls=%d idx=%d last=%v, want 2, 2, %v", rem.calls, h.idx, rem.last, realEps[2])
213		}
214	}
215	
216	// mustAP parses a single "ip:port" endpoint or fails the test.
217	func mustAP(t *testing.T, s string) netip.AddrPort {
218		t.Helper()
219		ap, err := netip.ParseAddrPort(s)
220		if err != nil {
221			t.Fatalf("parse endpoint %q: %v", s, err)
222		}
223		return ap
224	}
225	
226	// litSpec builds a literal failoverSpec (fixed single-entry expansion), as resolveEndpoints
227	// produces for an IP-literal endpoint entry.
228	func litSpec(t *testing.T, s string) failoverSpec {
229		t.Helper()
230		ap := mustAP(t, s)
231		return failoverSpec{spec: config.EndpointSpec{Addr: ap}, addrs: []netip.AddrPort{ap}}
232	}
233	
234	// nameSpec builds a hostname failoverSpec carrying an initial expansion (which may be
235	// empty, modelling a not-yet-resolved hostname at boot).
236	func nameSpec(host string, port uint16, addrs ...netip.AddrPort) failoverSpec {
237		return failoverSpec{spec: config.EndpointSpec{Host: host, Port: port, IsName: true}, addrs: addrs}
238	}
239	
240	// TestHubFailoverStandbyRecordSwapNoRepoint is acceptance (1): swapping a STANDBY spec's
241	// expansion (a hostname re-resolving off the active spec) must NOT touch the bond — zero
242	// SetPeerRemote, zero re-handshake — and must leave the active pointer on its own entry.
243	func TestHubFailoverStandbyRecordSwapNoRepoint(t *testing.T) {
244		active := mustAP(t, "203.0.113.1:51820")
245		specs := []failoverSpec{
246			litSpec(t, "203.0.113.1:51820"),                                         // spec 0: active literal
247			nameSpec("standby.example.com", 51820, mustAP(t, "198.51.100.7:51820")), // spec 1: standby hostname
248		}
249		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateUp}}
250		rem := &recordingRemote{}
251		handshakes := 0
252		clk := &fakeClock{now: time.Unix(1000, 0)}
253		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
254		if h.activeSpec != 0 || h.activeAddr != active {
255			t.Fatalf("boot active = (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, active)
256		}
257	
258		// The standby hostname re-resolves onto a DIFFERENT record.
259		h.updateResolution(1, []netip.AddrPort{mustAP(t, "192.0.2.9:51820")})
260	
261		if rem.calls != 0 || handshakes != 0 {
262			t.Fatalf("standby-record swap touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
263		}
264		if h.activeSpec != 0 || h.activeAddr != active {
265			t.Fatalf("standby-record swap moved the active pointer to (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, active)
266		}
267		if h.idx != 0 {
268			t.Fatalf("active flattened idx = %d, want 0 (unchanged; the standby follows the active spec)", h.idx)
269		}
270	}
271	
272	// TestHubFailoverActiveIPChangeRepointsOnce is acceptance (2): when the ACTIVE spec (a
273	// hostname) re-resolves off its current AddrPort, the active endpoint's IP has changed, so
274	// the bond is repointed via EXACTLY one SetPeerRemote + one re-handshake to the new record.
275	func TestHubFailoverActiveIPChangeRepointsOnce(t *testing.T) {
276		oldA := mustAP(t, "203.0.113.1:51820")
277		newA := mustAP(t, "203.0.113.2:51820")
278		specs := []failoverSpec{
279			nameSpec("hub.example.com", 51820, oldA), // spec 0: active hostname
280			litSpec(t, "198.51.100.7:51820"),         // spec 1: literal standby
281		}
282		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
283		rem := &recordingRemote{}
284		handshakes := 0
285		clk := &fakeClock{now: time.Unix(1000, 0)}
286		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
287		if h.activeSpec != 0 || h.activeAddr != oldA {
288			t.Fatalf("boot active = (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, oldA)
289		}
290	
291		h.updateResolution(0, []netip.AddrPort{newA})
292	
293		if rem.calls != 1 {
294			t.Fatalf("active-IP change SetPeerRemote=%d, want exactly 1", rem.calls)
295		}
296		if rem.last != newA {
297			t.Fatalf("repointed remote = %v, want new active record %v", rem.last, newA)
298		}
299		if handshakes != 1 {
300			t.Fatalf("active-IP change re-handshakes=%d, want exactly 1", handshakes)
301		}
302		if h.activeSpec != 0 || h.activeAddr != newA {
303			t.Fatalf("active pointer = (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, newA)
304		}
305	}
306	
307	// TestHubFailoverUnchangedActiveIPNoRepoint is acceptance (3): re-resolving the ACTIVE spec
308	// onto a record set that STILL contains the current active AddrPort is a no-op for the bond
309	// (Q31/D32 suppression) — zero SetPeerRemote, zero re-handshake.
310	func TestHubFailoverUnchangedActiveIPNoRepoint(t *testing.T) {
311		active := mustAP(t, "203.0.113.1:51820")
312		extra := mustAP(t, "203.0.113.9:51820")
313		specs := []failoverSpec{
314			nameSpec("hub.example.com", 51820, active), // spec 0: active hostname
315			litSpec(t, "198.51.100.7:51820"),           // spec 1: literal standby
316		}
317		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
318		rem := &recordingRemote{}
319		handshakes := 0
320		clk := &fakeClock{now: time.Unix(1000, 0)}
321		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
322	
323		// Re-resolve: the record set changed (grew) but STILL contains the active AddrPort.
324		h.updateResolution(0, []netip.AddrPort{active, extra})
325	
326		if rem.calls != 0 || handshakes != 0 {
327			t.Fatalf("unchanged active IP touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
328		}
329		if h.activeSpec != 0 || h.activeAddr != active {
330			t.Fatalf("active pointer = (%d,%v), want (0,%v) (survived the swap)", h.activeSpec, h.activeAddr, active)
331		}
332		if h.idx != 0 {
333			t.Fatalf("active flattened idx = %d, want 0", h.idx)
334		}
335	}
336	
337	// TestHubFailoverIdxReMapsOnExpansionGrowShrink is acceptance (4): when a STANDBY spec
338	// ordered BEFORE the active entry grows or shrinks, the active entry's FLATTENED index
339	// re-maps to its new offset — the active identity is spec-scoped, not a frozen flat index —
340	// while the bond is never touched (standby-only change).
341	func TestHubFailoverIdxReMapsOnExpansionGrowShrink(t *testing.T) {
342		activeLit := mustAP(t, "198.51.100.7:51820")
343		specs := []failoverSpec{
344			nameSpec("early.example.com", 51820), // spec 0: hostname, EMPTY at boot
345			litSpec(t, "198.51.100.7:51820"),     // spec 1: literal → boot-active (flat[0])
346		}
347		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
348		rem := &recordingRemote{}
349		handshakes := 0
350		clk := &fakeClock{now: time.Unix(1000, 0)}
351		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
352		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 0 {
353			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, activeLit)
354		}
355	
356		// Grow the earlier standby spec 0 from [] to two records: active flat idx 0 → 2.
357		h.updateResolution(0, []netip.AddrPort{mustAP(t, "203.0.113.1:51820"), mustAP(t, "203.0.113.2:51820")})
358		if rem.calls != 0 || handshakes != 0 {
359			t.Fatalf("growing a standby spec touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
360		}
361		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 2 {
362			t.Fatalf("after grow: active=(%d,%v) idx=%d, want (1,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, activeLit)
363		}
364	
365		// Shrink the earlier standby spec 0 to one record: active flat idx 2 → 1.
366		h.updateResolution(0, []netip.AddrPort{mustAP(t, "203.0.113.1:51820")})
367		if rem.calls != 0 || handshakes != 0 {
368			t.Fatalf("shrinking a standby spec touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
369		}
370		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 1 {
371			t.Fatalf("after shrink: active=(%d,%v) idx=%d, want (1,%v) idx=1", h.activeSpec, h.activeAddr, h.idx, activeLit)
372		}
373	}
374	
375	// TestPeerNeedsHubFailover is acceptance (5): a single-IP-literal peer warrants NO
376	// controller (byte-for-byte pre-G5), while a peer with any hostname spec OR >= 2 flattened
377	// literals does. This is the exact construction gate startHubFailover applies per peer.
378	func TestPeerNeedsHubFailover(t *testing.T) {
379		lit := func(s string) config.EndpointSpec { return config.EndpointSpec{Addr: mustAP(t, s)} }
380		name := func(h string, p uint16) config.EndpointSpec {
381			return config.EndpointSpec{Host: h, Port: p, IsName: true}
382		}
383	
384		cases := []struct {
385			name string
386			peer config.Peer
387			want bool
388		}{
389			{
390				name: "single IP literal → no controller",
391				peer: config.Peer{
392					Endpoints:     mustEndpoints(t, "203.0.113.1:51820"),
393					EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820")},
394				},
395				want: false,
396			},
397			{
398				name: "two IP literals → controller",
399				peer: config.Peer{
400					Endpoints:     mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820"),
401					EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820"), lit("198.51.100.7:51820")},
402				},
403				want: true,
404			},
405			{
406				name: "single hostname → controller (may re-resolve onto a new IP)",
407				peer: config.Peer{
408					Endpoints:     nil,
409					EndpointSpecs: []config.EndpointSpec{name("hub.example.com", 51820)},
410				},
411				want: true,
412			},
413			{
414				name: "hostname + literal → controller",
415				peer: config.Peer{
416					Endpoints:     mustEndpoints(t, "203.0.113.1:51820"),
417					EndpointSpecs: []config.EndpointSpec{name("hub.example.com", 51820), lit("203.0.113.1:51820")},
418				},
419				want: true,
420			},
421		}
422		for _, tc := range cases {
423			t.Run(tc.name, func(t *testing.T) {
424				if got := peerNeedsHubFailover(tc.peer); got != tc.want {
425					t.Fatalf("peerNeedsHubFailover = %v, want %v", got, tc.want)
426				}
427			})
428		}
429	}
430	
431	// TestHubFailoverCrossSpecDuplicateNoSpuriousReMap is acceptance (6), the R70 case: a
432	// hostname STANDBY spec re-resolving onto the SAME AddrPort as the active spec's own literal
433	// must NOT move the active pointer (spec-scoped identity, not bare value) and must not touch
434	// the bond; a subsequent hub-loss advance then walks the FLATTENED order correctly past the
435	// duplicate rather than being confused by it.
436	func TestHubFailoverCrossSpecDuplicateNoSpuriousReMap(t *testing.T) {
437		dup := mustAP(t, "203.0.113.1:51820")   // shared AddrPort across specs 0 and 1
438		tail := mustAP(t, "198.51.100.7:51820") // spec 2 literal standby
439		specs := []failoverSpec{
440			nameSpec("shadow.example.com", 51820), // spec 0: hostname, EMPTY at boot
441			litSpec(t, "203.0.113.1:51820"),       // spec 1: literal dup → boot-active (flat[0])
442			litSpec(t, "198.51.100.7:51820"),      // spec 2: literal standby
443		}
444		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
445		rem := &recordingRemote{}
446		handshakes := 0
447		clk := &fakeClock{now: time.Unix(1000, 0)}
448		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
449		if h.activeSpec != 1 || h.activeAddr != dup || h.idx != 0 {
450			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, dup)
451		}
452	
453		// The standby hostname (spec 0) re-resolves onto the SAME AddrPort as the active spec-1
454		// literal. A bare-value re-map would rebind the active pointer to spec 0's duplicate at
455		// flat index 0; the spec-scoped identity must keep it on spec 1 (now at flat index 1).
456		h.updateResolution(0, []netip.AddrPort{dup})
457		if rem.calls != 0 || handshakes != 0 {
458			t.Fatalf("cross-spec duplicate re-resolution touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
459		}
460		if h.activeSpec != 1 || h.activeAddr != dup {
461			t.Fatalf("active pointer spuriously re-mapped to (%d,%v), want (1,%v) (own spec's entry)", h.activeSpec, h.activeAddr, dup)
462		}
463		if h.idx != 1 {
464			t.Fatalf("active flattened idx = %d, want 1 (spec-1 dup, past spec-0's duplicate at 0)", h.idx)
465		}
466	
467		// A subsequent hub-loss advance must walk the flattened order to spec 2's tail literal
468		// at flat index 2 — NOT stall on the duplicate at index 0/1.
469		clk.advance(testSettle + time.Second)
470		h.check()
471		if rem.calls != 1 || rem.last != tail {
472			t.Fatalf("advance after duplicate: SetPeerRemote=%d last=%v, want 1 and %v (flattened order to spec-2 tail)", rem.calls, rem.last, tail)
473		}
474		if h.activeSpec != 2 || h.activeAddr != tail || h.idx != 2 {
475			t.Fatalf("post-advance active = (%d,%v) idx=%d, want (2,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, tail)
476		}
477		if handshakes != 1 {
478			t.Fatalf("advance re-handshakes=%d, want 1", handshakes)
479		}
480	}
